async function hashSenha(senha) {
const encoder = new TextEncoder();
const data = encoder.encode(senha);
const hashBuffer = await crypto.subtle.digest('SHA-256', data);
const hashArray = Array.from(new Uint8Array(hashBuffer));
return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');}

function getCredenciais() {
return { user: 'admin', hash: null };}

// ============================================================
// Verifica perfil pelo e-mail digitado na tela de login
// Admin  → mostra link "Esqueci minha senha"
// Outros → mantém escondido
// ============================================================
async function verificarPerfilEmail(email) {
  const btn = document.getElementById('btn-esqueci-senha');
  if (!btn) return;

  // Esconde por padrão
  btn.style.display = 'none';

  if (!email || !email.includes('@')) return;

  try {
    const { data } = await supa
      .from('perfis')
      .select('perfil')
      .eq('email', email.toLowerCase().trim())
      .single();

    // Só exibe o link se for admin
    if (data?.perfil === 'admin') {
      btn.style.display = 'block';
    }
  } catch(e) {
    // Silencioso — não revela se o e-mail existe ou não
    btn.style.display = 'none';
  }
}

// ── Controle de tentativas de login (bloqueio) ───────────────
const SCA_MAX_TENTATIVAS = 5;

async function checarBloqueio(email) {
  try {
    const { data } = await supa.from('perfis').select('bloqueado, perfil').eq('email', email.toLowerCase().trim()).single();
    if (data?.perfil === 'admin') return false;
    return data?.bloqueado === true;
  } catch(e) { return false; }
}

async function registrarTentativaFalha(email) {
  try {
    const { data } = await supa.from('perfis').select('tentativas_login, perfil').eq('email', email.toLowerCase().trim()).single();
    if (!data || data.perfil === 'admin') return;
    const tentativas = (data.tentativas_login || 0) + 1;
    const bloqueado  = tentativas >= SCA_MAX_TENTATIVAS;
    await supa.from('perfis').update({ tentativas_login: tentativas, bloqueado }).eq('email', email.toLowerCase().trim());
    if (bloqueado) {
      window.registrarLogSeguranca && window.registrarLogSeguranca('bloqueio', 'Conta bloqueada após ' + SCA_MAX_TENTATIVAS + ' tentativas', email);
    }
  } catch(e) { console.warn('[SCA] Erro ao registrar tentativa:', e); }
}

async function resetarTentativas(email) {
  try {
    await supa.from('perfis').update({ tentativas_login: 0, bloqueado: false }).eq('email', email.toLowerCase().trim());
  } catch(e) {}
}

async function doLogin() {
const email = document.getElementById('login-user').value.trim();
const password = document.getElementById('login-pass').value;

// ── Verifica se está bloqueado ───────────────────────────────
const estaBloqueado = await checarBloqueio(email);
if (estaBloqueado) {
  const err = document.getElementById('login-erro');
  err.textContent = '🔒 Conta bloqueada após 5 tentativas. Contate o administrador.';
  err.style.display = 'block';
  setTimeout(() => { err.style.display = 'none'; err.textContent = ''; }, 5000);
  window.registrarLogSeguranca && window.registrarLogSeguranca('login_erro', 'Tentativa de acesso em conta bloqueada', email);
  return;
}

const { data, error } = await supa.auth.signInWithPassword({ email, password });

if (error) {
const err = document.getElementById('login-erro');
err.style.display = 'block';
setTimeout(() => err.style.display = 'none', 3000);
window.registrarLogSeguranca && window.registrarLogSeguranca('login_erro', 'Tentativa de login — senha errada', email);
await registrarTentativaFalha(email);
} else {
await resetarTentativas(email);
const nomeExibido = data.user?.email || email;
/* ── Abre o app imediatamente, busca chave do Vault em background ── */
_abrirApp(nomeExibido);
window.SCA_EMAIL = email;
// Pega IP e registra login
fetch('https://api.ipify.org?format=json')
  .then(r => r.json())
  .then(ipData => {
    const ip = ipData?.ip || 'desconhecido';
    window.registrarLogSeguranca && window.registrarLogSeguranca('login_ok', 'Login realizado — IP ' + ip, email);
  })
  .catch(() => {
    window.registrarLogSeguranca && window.registrarLogSeguranca('login_ok', 'Login realizado — IP desconhecido', email);
  });
const token = data.session?.access_token;
fetch(window.SUPA_URL + '/functions/v1/get-cripto-key', {
  headers: { 'Authorization': 'Bearer ' + token, 'apikey': window.SUPA_KEY }
})
.then(resp => resp.ok ? resp.json() : null)
.then(json => { if (json?.key) window._SCA_KEY_VAULT = json.key; })
.catch(e => console.warn('[SCA-Cripto] Vault indisponível, usando fallback.', e));
}}

function _switchCard(mostrar) {
['login-box', 'esqueci-box', 'nova-senha-box'].forEach(function(id) {
document.getElementById(id).style.display = (id === mostrar) ? 'block' : 'none';
});}

function mostrarEsqueciSenha() {
_switchCard('esqueci-box');
var msgEl = document.getElementById('esqueci-msg');
msgEl.style.display = 'none';
msgEl.textContent = '';
var email = document.getElementById('login-user').value;
if (email) document.getElementById('esqueci-email').value = email;}

function voltarLogin() {
_switchCard('login-box');}

async function enviarResetSenha() {
var email = document.getElementById('esqueci-email').value.trim();
var msgEl = document.getElementById('esqueci-msg');
var btn = document.querySelector('#esqueci-box .login-btn');

function showMsg(texto, ok) {
msgEl.textContent = texto;
msgEl.style.background = ok ? 'rgba(46,204,113,.2)' : 'rgba(231,76,60,.2)';
msgEl.style.color = ok ? '#00e676' : '#ff6b6b';
msgEl.style.border = ok ? '1px solid rgba(46,204,113,.35)' : '1px solid rgba(231,76,60,.35)';
msgEl.style.display = 'block';}

if (!email) { showMsg('❌ Digite seu e-mail.', false); return; }

if (btn) { btn.disabled = true; btn.textContent = '⏳ Enviando...'; }

try {
const { error } = await supa.auth.resetPasswordForEmail(email, {
redirectTo: 'https://sca-sistema.github.io/login/'
});

if (error) {
showMsg('❌ Erro: ' + error.message, false);
} else {
showMsg('✅ E-mail enviado! Verifique sua caixa de entrada.', true);}
} catch(e) {
showMsg('❌ Falha na conexão: ' + (e.message || e), false);
} finally {
if (btn) { btn.disabled = false; btn.textContent = '📧 Enviar Link de Recuperação'; }}}

async function salvarNovaSenha() {
const senha = document.getElementById('nova-senha-input').value;
const conf  = document.getElementById('nova-senha-conf').value;
const msgEl = document.getElementById('nova-senha-msg');

if (!senha || senha.length < 6) {
msgEl.textContent = '❌ Senha deve ter no mínimo 6 caracteres.';
msgEl.style.background = 'rgba(231,76,60,.2)';
msgEl.style.color = '#ff6b6b';
msgEl.style.display = 'block';
return;}
if (senha !== conf) {
msgEl.textContent = '❌ As senhas não coincidem.';
msgEl.style.background = 'rgba(231,76,60,.2)';
msgEl.style.color = '#ff6b6b';
msgEl.style.display = 'block';
return;}

const { error } = await supa.auth.updateUser({ password: senha });

if (error) {
msgEl.textContent = '❌ Erro: ' + error.message;
msgEl.style.background = 'rgba(231,76,60,.2)';
msgEl.style.color = '#ff6b6b';
} else {
msgEl.textContent = '✅ Senha alterada com sucesso! Faça login.';
msgEl.style.background = 'rgba(46,204,113,.2)';
msgEl.style.color = '#00e676';
msgEl.style.display = 'block';
setTimeout(() => voltarLogin(), 2500);}
msgEl.style.display = 'block';}

supa.auth.onAuthStateChange((event, session) => {
if (event === 'PASSWORD_RECOVERY') {
_switchCard('nova-senha-box');}
});

(async () => {
try {
const { data } = await supa.auth.getSession();
if (data && data.session && data.session.user) {
const nomeExibido = data.session.user.email || 'admin';
_abrirApp(nomeExibido);}
} catch(e) { console.warn('Erro ao verificar sessão:', e); }
})();

// ============================================================
// ============================================================
// RBAC v2 — Estrutura final de 3 níveis
//
// Nível 1 — admin   → controle total, vê e edita tudo
// Nível 2 — gerente → vê tudo de todos, só leitura nos dados
//                     cadastra e gerencia colaboradores comuns
// Nível 3 — comum   → trabalha só no próprio escopo (RLS no banco)
//                     não acessa painel de usuários
// ============================================================

async function verificarEAplicarPerfil() {
  try {
    const { data: { user } } = await supa.auth.getUser();
    if (!user) return;
    window.SCA_USER_ID = user.id; // salva ID do usuário logado

    const { data: perfilData } = await window.supa
      .from('perfis')
      .select('perfil')
      .eq('id', user.id)
      .single();

    window.SCA_PERFIL = perfilData?.perfil || 'comum';
    console.log('[SCA] 👤 Perfil carregado:', window.SCA_PERFIL);

    // ── Visibilidade do botão Colaboradores ──────────────────
    // admin e gerente veem; comum não vê
    aplicarVisibilidadeColaboradores(window.SCA_PERFIL);

    // ── Modo GERENTE — somente leitura nos dados de clientes ─
    if (window.SCA_PERFIL === 'gerente') {
      setTimeout(() => {
        // Bloqueia botões de edição de dados (mas NÃO os botões de colaboradores)
        document.querySelectorAll(
          '.btn-save, .btn-del, .btn-new, .btn-edit, .action-btn, ' +
          '.btn-green, [onclick*="salvar"], [onclick*="excluir"], ' +
          '[onclick*="novoCliente"], [onclick*="editarCliente"]'
        ).forEach(btn => {
          // Preserva botões dentro da página de colaboradores
          if (btn.closest('#page-colaboradores')) return;
          btn.style.display = 'none';
        });

        // Campos de dados somente leitura (preserva página de colaboradores)
        document.querySelectorAll(
          '.form-input, input:not([type=button]):not([type=submit]), textarea, select'
        ).forEach(el => {
          if (el.closest('#page-colaboradores')) return;
          el.setAttribute('readonly', true);
          el.setAttribute('disabled', true);
          el.style.background = '#f0f0f0';
          el.style.cursor = 'not-allowed';
          el.style.pointerEvents = 'none';
        });

        // Faixa de aviso no topo
        if (!document.getElementById('sca-gerente-aviso')) {
          const aviso = document.createElement('div');
          aviso.id = 'sca-gerente-aviso';
          aviso.style.cssText = [
            'background:#2c5282', 'color:#fff', 'text-align:center',
            'padding:7px 16px', 'font-size:.78rem', 'font-weight:700',
            'letter-spacing:1.2px', 'position:sticky', 'top:0', 'z-index:999',
            'box-shadow:0 2px 8px rgba(0,0,0,.2)'
          ].join(';');
          aviso.textContent = '👁️ MODO SUPERVISÃO — Você está logado como Gerente. Dados são somente leitura.';
          const app = document.getElementById('app');
          if (app) app.prepend(aviso);
        }
        console.log('[SCA] 👁️ Modo gerente ativado — edições bloqueadas nos dados.');
      }, 900);
    }

    // ── Modo COMUM — sem acesso a colaboradores (garantia extra) ─
    // Exibe painel de monitor só pro admin
if (window.SCA_PERFIL === 'admin') {
  window.carregarMonitor && window.carregarMonitor();
  window.carregarBloqueados && window.carregarBloqueados();
} else {
  const p = document.getElementById('painel-monitor');
  if (p) p.style.display = 'none';
  const pb = document.getElementById('painel-bloqueados');
  if (pb) pb.style.display = 'none';
}

if (window.SCA_PERFIL === 'comum') {
      const btnColab = document.getElementById('nav-btn-colaboradores');
      if (btnColab) btnColab.style.display = 'none';
    }

  } catch(e) {
    console.warn('[SCA] Erro ao verificar perfil:', e);
    window.SCA_PERFIL = 'comum'; // fallback seguro
  }
}
function _abrirApp(nomeUsuario) {
const ls = document.getElementById('login-screen');
ls.classList.add('hide');
setTimeout(async () => {
ls.style.display = 'none';
document.getElementById('app').style.display = 'block';
document.getElementById('topbar-username').textContent = nomeUsuario;
showPage('home', document.querySelector('[onclick*="\'home\'"]'));
// ── ORDEM GARANTIDA ──────────────────────────────────────
// 1. carregarDadosAposLogin() resolve o perfil internamente
//    (await síncrono) ANTES de buscar os dados do banco.
// 2. verificarEAplicarPerfil() usa window.SCA_PERFIL que já
//    está definido — sem race condition.
if (window.carregarDadosAposLogin) await window.carregarDadosAposLogin();
verificarEAplicarPerfil();
}, 500);}

