function calcTempoOcupacao() {
  const anoEl = document.getElementById('prop-ger-ano-ocup');
  const tempoEl = document.getElementById('prop-ger-tempo-ocup');
  if (!anoEl || !tempoEl) return;
  const ano = parseInt(anoEl.value, 10);
  if (!ano || ano < 1900 || ano > new Date().getFullYear()) {
    tempoEl.value = '';
    return;
  }
  const anos = new Date().getFullYear() - ano;
  tempoEl.value = anos + (anos === 1 ? ' ANO' : ' ANOS');
}

function calcAreas() {
  const g = id => parseFloat((document.getElementById(id)?.value || '0').replace(/\./g,'').replace(',','.')) || 0;
  const fmt = v => v > 0 ? v.toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2}) : '';

  const total  = g('prop-area-total');
  const agri   = g('prop-area-agri');
  const past   = g('prop-area-past');
  const res    = g('prop-area-res');
  const app    = g('prop-area-app');
  const inapta = g('prop-area-inapta');
  const proj   = g('prop-area-proj');

  const aprov  = agri + past + res + app + inapta;
  const nutil  = total > 0 ? Math.max(0, total - aprov) : 0;
  const perc   = total > 0 ? (aprov / total * 100) : 0;
  const saldo  = total > 0 ? total - proj : 0;

  const elAprov = document.getElementById('prop-area-aprov');
  const elNutil = document.getElementById('prop-area-nutil');
  const elPerc  = document.getElementById('prop-area-perc');
  const elSaldo = document.getElementById('prop-area-saldo');
  const elAlerta = document.getElementById('prop-area-alerta');

  if (elAprov) elAprov.value = fmt(aprov);
  if (elNutil) elNutil.value = fmt(nutil);
  if (elPerc)  elPerc.value  = perc > 0 ? perc.toLocaleString('pt-BR',{minimumFractionDigits:1,maximumFractionDigits:1}) + ' %' : '';
  if (elSaldo) elSaldo.value = saldo !== 0 ? fmt(Math.abs(saldo)) + (saldo < 0 ? ' (excede)' : '') : '';
  if (elAlerta) elAlerta.style.display = (total > 0 && aprov > total) ? 'block' : 'none';
}

function calcBenfeitorias() {
  const g = id => parseFloat((document.getElementById(id)?.value || '0').replace(/\./g,'').replace(',','.')) || 0;
  const total = g('prop-benf-qtd') * g('prop-benf-vunit');
  const el = document.getElementById('prop-benf-vtotal');
  if (el) el.value = total > 0 ? total.toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2}) : '';
}

