let clientes = [];
window.clientes = clientes;
let clIdx = -1;
let clModoEdicao = false;

function syncClientes() {
  // Sincroniza variável local com window.clientes (atualizado pelo Supabase)
  if (window.clientes && window.clientes !== clientes) {
    clientes = window.clientes;
  }
  if (typeof window.clIdx !== 'undefined' && window.clIdx !== clIdx) {
    clIdx = window.clIdx;
  }
}

function salvarClientesStorage() {
syncClientes();
window.clientes = clientes;
atualizarDropdownElaboracao();
if (!window.supa) { console.warn('Supabase não inicializado.'); return; }
if (clIdx < 0 || !clientes[clIdx]) { return; }
const cpfKey = (clientes[clIdx].cpf || '').replace(/\D/g,'');
if (cpfKey) {
  window.fbSalvar('clientes', cpfKey, clientes[clIdx]);
} else {
  console.warn('Cliente sem CPF — não foi salvo no Supabase:', clientes[clIdx].nome);
}}

function clStatus(msg, tipo) {
const el = document.getElementById('cl-status');
if (!el) return;
el.style.display = '';
el.textContent = msg;
el.style.background = tipo === 'ok' ? '#d4edda' : tipo === 'err' ? '#f8d7da' : '#fff3cd';
el.style.color     = tipo === 'ok' ? '#155724' : tipo === 'err' ? '#721c24' : '#856404';
el.style.border    = '1px solid ' + (tipo === 'ok' ? '#c3e6cb' : tipo === 'err' ? '#f5c6cb' : '#ffc107');
setTimeout(() => { if (el) el.style.display = 'none'; }, 3000);}

function exibirCliente(i) {
syncClientes();
if (i < 0 || i >= clientes.length) {
limparCamposCliente();
return;}
const c = clientes[i];
document.getElementById('cl-codigo').value = c.codigo || '';
document.getElementById('cl-cpf').value    = c.cpf    || '';
document.getElementById('cl-nome').value   = c.nome   || '';
document.getElementById('cl-data').value   = c.data_cadastro || c.data || '';
const box = document.getElementById('cl-foto-box');
const _cpfFoto = (c.cpf || '').replace(/\D/g,'');
const _supaUrl = window.SUPA_URL;
if (_cpfFoto) {
  const _urlJpg = _supaUrl + '/storage/v1/object/public/fotos_clientes/' + _cpfFoto + '.jpg';
  const _urlPng = _supaUrl + '/storage/v1/object/public/fotos_clientes/' + _cpfFoto + '.png';
  const _img = new Image();
  _img.onload = () => { box.innerHTML = '<img src="' + _urlJpg + '?t=' + Date.now() + '" style="width:100%;height:100%;object-fit:cover;" />'; };
  _img.onerror = () => {
    const _img2 = new Image();
    _img2.onload = () => { box.innerHTML = '<img src="' + _urlPng + '?t=' + Date.now() + '" style="width:100%;height:100%;object-fit:cover;" />'; };
    _img2.onerror = () => { box.innerHTML = '<span style="font-size:2.5rem;color:#888;">👤</span>'; };
    _img2.src = _urlPng;
  };
  _img.src = _urlJpg;
} else {
  box.innerHTML = '<span style="font-size:2.5rem;color:#888;">👤</span>';
}
if (typeof renderizarOperacoes === 'function')    renderizarOperacoes(i);
if (typeof renderizarAnexos === 'function')       renderizarAnexos(i);
// Busca todos os dados do cliente do Supabase
if (typeof window.carregarDadosClienteSupabase === 'function' && c.id) {
  window.carregarDadosClienteSupabase(c.id);
  if (typeof window.safCarregar === 'function') window.safCarregar(c.id);
} else {
  if (typeof carregarDadosPessoais === 'function')   carregarDadosPessoais(i);
  if (typeof carregarEndereco === 'function')        carregarEndereco(i);
  if (typeof carregarDadosBancarios === 'function')  carregarDadosBancarios(i);
  if (typeof carregarOperacaoAtual === 'function')   carregarOperacaoAtual(i);
  if (typeof carregarParticipantes === 'function')   carregarParticipantes(i);
  if (typeof carregarAgricola === 'function')        carregarAgricola(i);
  if (typeof carregarPecuaria === 'function')        carregarPecuaria(i);
  if (typeof carregarPropriedade === 'function')     carregarPropriedade(i);
  if (typeof window.safCarregar === 'function' && c.id) window.safCarregar(c.id);
}}

function limparCamposCliente() {
['cl-codigo','cl-cpf','cl-nome','cl-data'].forEach(id => {
const el = document.getElementById(id);
if (el) el.value = '';
});
document.getElementById('cl-foto-box').innerHTML = '<span style="font-size:2.5rem;color:#888;">👤</span>';
}

function novoCliente() {
syncClientes();
clModoEdicao = true;
clIdx = -1;
limparCamposCliente();
document.getElementById('cl-codigo').value = '...';
document.getElementById('cl-data').value = new Date().toISOString().split('T')[0];
document.getElementById('cl-cpf').focus();
clStatus('Novo cadastro iniciado. Preencha os campos e clique em 💾 Salvar.', 'info');
// Busca o próximo código no Supabase
if (window.supa) {
  window.supa.from('clientes').select('codigo').order('codigo', { ascending: false }).limit(1)
    .then(({ data }) => {
      const ultimo = (data && data[0] && data[0].codigo) ? parseInt(data[0].codigo) : 0;
      const proximo = ultimo + 1;
      const codEl = document.getElementById('cl-codigo');
      if (codEl) codEl.value = proximo;
    }).catch(() => {
      const codEl = document.getElementById('cl-codigo');
      if (codEl) codEl.value = (clientes.length > 0 ? Math.max(...clientes.map(c => parseInt(c.codigo)||0)) + 1 : 1);
    });
} else {
  const proximo = clientes.length > 0 ? Math.max(...clientes.map(c => parseInt(c.codigo)||0)) + 1 : 1;
  document.getElementById('cl-codigo').value = proximo;
}}

function editarCliente() {
syncClientes();
if (clIdx < 0 || clIdx >= clientes.length) {
clStatus('Nenhum cliente selecionado para editar.', 'err'); return;}
clModoEdicao = true;
document.getElementById('cl-nome').focus();
clStatus('Modo edição ativo. Altere os campos e clique em 💾 Salvar.', 'info');}

async function salvarCliente() {
if (typeof syncClientes === 'function') syncClientes();
const codigo = (document.getElementById('cl-codigo')||{}).value?.trim()||'';
const cpf    = (document.getElementById('cl-cpf')   ||{}).value?.trim()||'';
const nome   = (document.getElementById('cl-nome')  ||{}).value?.trim()||'';
const data   = (document.getElementById('cl-data')  ||{}).value||'';
if (!cpf || !nome) { clStatus('❌ CPF e Nome são obrigatórios!', 'err'); return; }
clStatus('⏳ Salvando...', 'info');
// Atualiza ou cria objeto em memória
const lista = window.clientes || [];
let idx = (typeof clIdx !== 'undefined') ? clIdx : -1;
let cl = (idx >= 0 && lista[idx]) ? lista[idx] : {};
// NUNCA usa cpf como id — mantém uuid real se já existir
if (!cl.id || !String(cl.id).includes('-')) cl.id = null;
cl.codigo = codigo; cl.cpf = cpf; cl.nome = nome; cl.data_cadastro = data;
if (idx < 0) { lista.push(cl); idx = lista.length - 1; window.clIdx = idx; clIdx = idx; }
else lista[idx] = cl;
window.clientes = lista;
clModoEdicao = false;
// Persiste no Supabase
if (window.supa) {
  try {
    const payload = { codigo, cpf, nome, data_cadastro:data||null,
      valor_total_receitas: cl.valor_total_receitas||0,
      status_processo: cl.status_processo||null, status_obs: cl.status_obs||null };
    let clienteSalvo;
    if (cl.id && String(cl.id).includes('-')) {
      // Atualiza registro existente (tem UUID real)
      const { data: upd, error } = await window.supa.from('clientes').update(payload).eq('id', cl.id).select().single();
      if (error) throw error;
      clienteSalvo = upd;
    } else {
      // Insere novo registro — Supabase gera o UUID automaticamente
      const { data: ins, error } = await window.supa.from('clientes').insert(payload).select().single();
      if (error) throw error;
      clienteSalvo = ins;
    }
    // Guarda o UUID real retornado pelo Supabase
    cl.id = clienteSalvo.id;
    lista[idx] = { ...cl, ...clienteSalvo };
    window.clientes = lista;
    clStatus('✅ Cliente salvo!', 'ok');
    if (typeof atualizarDropdownElaboracao==='function') atualizarDropdownElaboracao();
    if (typeof renderizarDashboard==='function') renderizarDashboard();
    if (typeof registrarLog==='function') registrarLog(idx===0&&lista.length===1?'➕':'✏️',
      'Cliente salvo: '+nome, nome);
  } catch(e) { clStatus('❌ Erro: '+(e.message||e), 'err'); return; }
} else { clStatus('✅ Salvo localmente.', 'info'); }
if (typeof exibirCliente==='function') exibirCliente(idx);}

function cancelarCliente() {
clModoEdicao = false;
if (clIdx >= 0) {
exibirCliente(clIdx);
clStatus('Edição cancelada.', 'info');
} else {
limparCamposCliente();}}

function excluirCliente() {
syncClientes();
if (clIdx < 0 || clIdx >= clientes.length) {
clStatus('Nenhum cliente selecionado.', 'err'); return;}
// Exclui direto no Supabase
const nome = clientes[clIdx].nome;
if (!confirm(`Excluir o cliente "${nome}"? Esta ação não pode ser desfeita.`)) return;
const clienteId = clientes[clIdx].id;
if (clienteId && window.supa) {
  window.supa.from('clientes').delete().eq('id', clienteId)
    .then(({error}) => { if (error) console.warn('Erro ao deletar:', error); });
}
clientes.splice(clIdx, 1);
window.clientes = clientes;
clIdx = clientes.length > 0 ? Math.min(clIdx, clientes.length - 1) : -1;
window.clIdx = clIdx;
exibirCliente(clIdx);
clStatus('🗑️ Cliente excluído.', 'info');}

function navCliente(dir) {
syncClientes();
const lista = (window.clientes && window.clientes.length > 0) ? window.clientes : clientes;
if (lista.length === 0) { clStatus('Nenhum cliente cadastrado.', 'info'); return; }
if (dir === 'first') clIdx = 0;
else if (dir === 'last')  clIdx = lista.length - 1;
else if (dir === 'prev')  clIdx = Math.max(0, clIdx - 1);
else if (dir === 'next')  clIdx = Math.min(lista.length - 1, clIdx + 1);
window.clIdx = clIdx;
if (window.clientes && window.clientes.length > 0) clientes = window.clientes;
exibirCliente(clIdx);}

function mascararCPF(input) {
let v = input.value.replace(/\D/g, '').substring(0, 11);
v = v.replace(/(\d{3})(\d)/, '$1.$2');
v = v.replace(/(\d{3})(\d)/, '$1.$2');
v = v.replace(/(\d{3})(\d{1,2})$/, '$1-$2');
input.value = v;}

async function carregarFotoCliente(input) {
if (!input.files || !input.files[0]) return;
if (typeof window.clIdx !== 'undefined' && window.clIdx >= 0) clIdx = window.clIdx;
if (typeof window.clientes !== 'undefined' && window.clientes.length > 0) clientes = window.clientes;
if (clIdx < 0 || !clientes[clIdx]) { alert('Selecione um cliente primeiro.'); return; }

const file = input.files[0];
const cpfKey = (clientes[clIdx].cpf || '').replace(/\D/g,'') || 'cliente_' + clIdx;
const box = document.getElementById('cl-foto-box');

const reader = new FileReader();
reader.onload = async function(e) {
const dataUrl = e.target.result;

// Preview imediato — igual ao logo da empresa
box.innerHTML = '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;position:relative;"><img src="' + dataUrl + '" style="width:100%;height:100%;object-fit:cover;opacity:.6;" /><div style="position:absolute;top:2px;right:4px;font-size:.6rem;color:#fff;background:rgba(0,0,0,.55);padding:1px 6px;border-radius:4px;">⬆️ Enviando...</div></div>';

// Upload — EXATAMENTE igual ao carregarLogoEmpresa
const ext = file.type.includes('png') ? 'png' : 'jpg';
const nomeArq = cpfKey + '.' + ext;
const BUCKET = 'fotos_clientes';
const ANONKEY = window.SUPA_KEY || SUPA_KEY;
const SUPAURL = window.SUPA_URL || SUPA_URL;
const uploadUrl = SUPAURL + '/storage/v1/object/' + BUCKET + '/' + nomeArq;
const publicUrl = SUPAURL + '/storage/v1/object/public/' + BUCKET + '/' + nomeArq;

let fotoUrl = null;
let erroMsg = null;
try {
  const resp = await fetch(uploadUrl, {
    method: 'PUT',
    headers: {
      'Authorization': 'Bearer ' + ANONKEY,
      'apikey': ANONKEY,
      'Content-Type': file.type,
      'x-upsert': 'true'
    },
    body: file
  });
  if (!resp.ok) {
    const errJson = await resp.json().catch(() => ({}));
    erroMsg = errJson.error || errJson.message || ('HTTP ' + resp.status);
    throw new Error(erroMsg);
  }
  fotoUrl = publicUrl + '?t=' + Date.now();
  console.log('✅ Foto enviada:', fotoUrl);
} catch(err) {
  erroMsg = erroMsg || (err && err.message) || 'Erro desconhecido';
  console.error('❌ Erro upload foto:', err);
}

if (fotoUrl) {
  clientes[clIdx].foto = fotoUrl;
  if (window.clientes) window.clientes[clIdx].foto = fotoUrl;
  box.innerHTML = '<img src="' + fotoUrl + '" style="width:100%;height:100%;object-fit:cover;" />';
} else {
  box.innerHTML = '<div style="position:relative;width:100%;height:100%;"><img src="' + dataUrl + '" style="width:100%;height:100%;object-fit:cover;" /><div style="position:absolute;bottom:0;left:0;right:0;background:rgba(231,76,60,.92);text-align:center;font-size:.58rem;color:#fff;padding:2px;">❌ ' + erroMsg + '</div></div>';
  alert('❌ Erro ao enviar foto:\n\n' + erroMsg);
}
};
reader.readAsDataURL(file);}

// Alias para compatibilidade com onchange="carregarFoto(this)"
