function calcularIdade() {
const nasc = document.getElementById('dp-nasc').value;
const idadeEl = document.getElementById('dp-idade');
if (!nasc) { idadeEl.value = ''; return; }
const hoje = new Date();
const dn   = new Date(nasc);
let idade   = hoje.getFullYear() - dn.getFullYear();
const m     = hoje.getMonth() - dn.getMonth();
if (m < 0 || (m === 0 && hoje.getDate() < dn.getDate())) idade--;
idadeEl.value = idade >= 0 ? idade + ' Anos' : '';}

