const TEMPLATE_BASE_URL = 'https://unexpected-maroon-6jkhzine0g.edgeone.app/'; // URL mantida como fallback

const templatesCache = {};

window._tmplCache = window._tmplCache || {};
function salvarTemplateLocal(nome, arrayBuffer) {
try {
const bytes = new Uint8Array(arrayBuffer);
let binary = '';
bytes.forEach(b => binary += String.fromCharCode(b));
window._tmplCache['tmpl_' + nome] = btoa(binary);
} catch(e) { console.warn('Erro ao salvar template em cache:', e); }}

function carregarTemplateLocal(nome) {
const b64 = (window._tmplCache && window._tmplCache['tmpl_' + nome]) || null;
if (!b64) return null;
try {
const binary = atob(b64);
const bytes = new Uint8Array(binary.length);
for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
return bytes.buffer;
} catch(e) { return null; }}

function removerTemplateLocal(nome) {
if (window._tmplCache) delete window._tmplCache['tmpl_' + nome];
delete templatesCache[nome];
renderizarStatusTemplates();}

async function baixarTemplateOnline(nome) {
// Templates .docx via EdgeOne desativados — usar Edge Function do Supabase para HTMLs
if (nome.endsWith('.html')) throw new Error('Use gerarDocHTML para templates HTML');
return null;
if (TEMPLATES_EMBUTIDOS[nome]) {
const b64 = TEMPLATES_EMBUTIDOS[nome];
const binary = atob(b64);
const bytes = new Uint8Array(binary.length);
for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
const buf = bytes.buffer;
templatesCache[nome] = buf;
salvarTemplateLocal(nome, buf);
return buf;}
const alvo = TEMPLATE_BASE_URL + nome;
const resp = await fetch(alvo);
if (!resp.ok) throw new Error('HTTP ' + resp.status);
const buf = await resp.arrayBuffer();
templatesCache[nome] = buf;
salvarTemplateLocal(nome, buf);
return buf;}

async function inicializarTemplatesDoStorage() {
TEMPLATE_FILES.forEach(nome => {
const buf = carregarTemplateLocal(nome);
if (buf) templatesCache[nome] = buf;
});
renderizarStatusTemplates();}

