// ── GERAR TODOS OS DOCX EM ZIP ────────────────────────────────
async function gerarTodosDOCX(btn) {
if (!clienteSelecionado) { mostrarStatus('⚠️ Selecione um cliente primeiro.', 'warn'); return; }
var labelOriginal = btn.innerHTML;
btn.classList.add('loading'); btn.innerHTML = '⏳ Gerando todos...'; btn.disabled = true;
try {
  const edgeUrl = SUPA_URL + '/functions/v1/gerar-documento';
  const session = await supa.auth.getSession();
  const token = session?.data?.session?.access_token || SUPA_KEY;

  // 1. Busca os dados uma única vez (usando o primeiro template como referência)
  const resp = await fetch(edgeUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
    body: JSON.stringify({ cpf: (clienteSelecionado.cpf || '').replace(/\D/g,''), template: DOCX_TEMPLATE_FILES[0] }),
  });
  if (!resp.ok) throw new Error('Erro ao buscar dados do cliente');
  const dados = await resp.json();

  const zipFinal = new JSZip();
  let count = 0;

  for (var i = 0; i < DOCX_TEMPLATE_FILES.length; i++) {
    var nomeArquivo = DOCX_TEMPLATE_FILES[i];
    try {
      // 2. Baixa cada template do bucket
      const { data: blob, error: errBucket } = await supa.storage.from('templates-docx').download(nomeArquivo);
      if (errBucket) { console.warn('Pulando ' + nomeArquivo + ': não encontrado no bucket'); continue; }

      // 3. Preenche com docxtemplater
      const arrayBuffer = await blob.arrayBuffer();
      const zip = new PizZip(arrayBuffer);
      // Injeta logo diretamente no ZIP antes de renderizar
      if (dados.logotipo) {
        try {
          const bin = atob(dados.logotipo);
          const arr = new Uint8Array(bin.length);
          for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
          zip.file('word/media/image2.png', arr);
        } catch(e) { console.warn('[SCA] Falha ao injetar logo no ZIP (lote):', e); }
      }
      const dadosSemLogo = Object.assign({}, dados);
      delete dadosSemLogo.logotipo;
      const doc = new window.Docxtemplater(zip, {
        delimiters: { start: '<<', end: '>>' },
        paragraphLoop: true,
        linebreaks: true,
      });
      doc.render(dadosSemLogo);

      const docxBlob = doc.getZip().generate({ type: 'uint8array' });
      zipFinal.file(nomeArquivo, docxBlob);
      count++;
      btn.innerHTML = '⏳ ' + count + '/' + DOCX_TEMPLATE_FILES.length + ' gerados...';
    } catch(err) {
      console.warn('Pulando ' + nomeArquivo + ':', err.message);
    }
  }

  const zipBlob = await zipFinal.generateAsync({ type: 'blob' });
  const nomeZip = (dados.a_nome_cliente || 'cliente').replace(/\s+/g,'_') + '_documentos.zip';
  saveAs(zipBlob, nomeZip);

  btn.classList.remove('loading'); btn.classList.add('success');
  btn.innerHTML = '✅ ' + count + ' gerados!';
  mostrarStatus('✅ ' + count + ' documentos DOCX gerados e baixados em ZIP para <b>' + dados.a_nome_cliente + '</b>!', 'ok');
} catch(e) {
  btn.classList.remove('loading'); btn.classList.add('error');
  btn.innerHTML = '❌ Erro';
  mostrarStatus('❌ Erro: ' + e.message, 'err');
  console.error(e);
} finally {
  btn.disabled = false;
  setTimeout(() => { btn.classList.remove('success','error'); btn.innerHTML = labelOriginal; }, 5000);
}}

const htmlTemplatesCache = {};

function substituirVariaveisHTML(html, dados) {
var chaves = Object.keys(dados);
for (var i = 0; i < chaves.length; i++) {
var chave = chaves[i];
var valor = String(dados[chave] || '');
var chaveEsc = chave.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
var re1 = new RegExp('&lt;&lt;\\s*' + chaveEsc + '\\s*&gt;&gt;', 'g');
var re2 = new RegExp('\\{\\{\\s*' + chaveEsc + '\\s*\\}\\}', 'g');
var re3 = new RegExp('<<\\s*' + chaveEsc + '\\s*>>', 'g');
html = html.replace(re1, valor);
html = html.replace(re2, valor);
html = html.replace(re3, valor);}
return html;}

async function fetchTemplateHTML(nomeArquivo) {
if (htmlTemplatesCache[nomeArquivo]) return htmlTemplatesCache[nomeArquivo];

const { data: blob, error } = await supa.storage
.from('templates-html')
.download(nomeArquivo);

if (error) {
if (error.message && error.message.toLowerCase().includes('jwt')) {
throw new Error('Sessão expirada. Por favor faça login novamente.');}
throw new Error('Erro ao baixar "' + nomeArquivo + '" do Supabase: ' + error.message);}

const html = await blob.text();
htmlTemplatesCache[nomeArquivo] = html;
return html;}

