function calcComissoes() {
// parseValorBR: trata tanto "97.974,12" (formato BR) quanto "97974.12" (número JS)
// Sem isso, o ponto de milhar e o ponto decimal se confundem ao carregar do banco.
const parseValorBR = function(v) {
  const s = String(v || '0');
  if (s.includes(',')) {
    // Formato BR: remove pontos de milhar, troca vírgula por ponto decimal
    return parseFloat(s.replace(/\./g,'').replace(',','.')) || 0;
  }
  // Número JS direto (ex: 97974.12 ou 97974)
  return parseFloat(s) || 0;
};
const rawValor = document.getElementById('oat-valor')?.value || '0';
const valor = parseValorBR(rawValor);
const rawBanc = (document.getElementById('oat-comis-banc-pct')?.value || '0').replace(/[^\d,\.]/g,'').replace(',','.');
const pBanc = parseFloat(rawBanc) || 0;
const rawPart = (document.getElementById('oat-comis-part-pct')?.value || '0').replace(/[^\d,\.]/g,'').replace(',','.');
const pPart = parseFloat(rawPart) || 0;
const fmtBR = n => n.toLocaleString('pt-BR', {minimumFractionDigits:2, maximumFractionDigits:2});
const rsBanc = document.getElementById('oat-comis-banc-rs');
const rsPart = document.getElementById('oat-comis-part-rs');
if (rsBanc) rsBanc.value = fmtBR(valor * pBanc / 100);
if (rsPart) rsPart.value = fmtBR(valor * pPart / 100);}

