async function salvarDadosEmpresa() {
const btn = document.querySelector('[onclick="salvarDadosEmpresa()"]');
const orig = btn.innerHTML;
btn.disabled = true; btn.innerHTML = '⏳ Salvando...'; btn.style.background = '#f39c12';
// Garante elemento de status
let statusEl = document.getElementById('emp-save-status');
if (!statusEl) {
  statusEl = document.createElement('span');
  statusEl.id = 'emp-save-status';
  statusEl.style.cssText = 'font-size:.82rem;font-weight:700;margin-left:12px;';
  btn.parentNode.appendChild(statusEl);
}
statusEl.textContent = '';
try {
const dados = {};
EMPRESA_CAMPOS.forEach(c => {
const el = document.getElementById('empresa-' + c);
if (el) dados[c] = el.value;
});
if (window._scaCache && window._scaCache.empresa_logo) dados.logo_url = window._scaCache.empresa_logo;
window._scaCache = window._scaCache || {};
window._scaCache.empresa = dados;
if (window.fbSalvar) await window.fbSalvar('empresa', 'empresa', dados);
btn.innerHTML = '✅ Salvo!'; btn.style.background = '#27ae60';
statusEl.style.color = '#1a5c38';
statusEl.textContent = '✅ Dados salvos com sucesso!';
setTimeout(() => { btn.innerHTML = orig; btn.style.background = ''; btn.disabled = false; statusEl.textContent = ''; }, 3000);
} catch(e) {
btn.innerHTML = '❌ Erro!'; btn.style.background = '#e74c3c';
statusEl.style.color = '#c0392b';
statusEl.textContent = '❌ Erro ao salvar. Tente novamente.';
setTimeout(() => { btn.innerHTML = orig; btn.style.background = ''; btn.disabled = false; statusEl.textContent = ''; }, 4000);
console.error('Erro ao salvar empresa:', e);
}}

