function cancelarMembro() {
document.getElementById('equipe-form').style.display = 'none';
document.getElementById('equipe-msg').style.display = 'none';}

async function salvarMembro() {
const msg = document.getElementById('equipe-msg');
function _msgEq(txt, tipo) {
  msg.innerHTML = txt;
  msg.style.background = tipo==='ok' ? '#d4edda' : '#f8d7da';
  msg.style.color      = tipo==='ok' ? '#155724' : '#721c24';
  msg.style.display = 'block';
}
const nome = document.getElementById('mem-nome').value.trim();
if (!nome) { _msgEq('❌ Nome completo é obrigatório.', 'err'); return; }
if (!window.supa) { _msgEq('❌ Conexão com banco não disponível.', 'err'); return; }
const supaId = document.getElementById('mem-id').value.trim();
const payload = {
  nome:            nome,
  cpf:             document.getElementById('mem-cpf').value.trim()   || null,
  data_nascimento: document.getElementById('mem-nasc').value.trim()  || null,
  cargo:           document.getElementById('mem-cargo').value.trim() || null,
  crea_cfb:        document.getElementById('mem-crea').value.trim()  || null,
  celular:         document.getElementById('mem-cel').value.trim()   || null,
  email:           document.getElementById('mem-email').value.trim() || null,
};
try {
  let result;
  if (supaId) {
    result = await window.supa.from('equipe').update(payload).eq('id', supaId).select();
  } else {
    result = await window.supa.from('equipe').insert(payload).select();
  }
  if (result.error) throw new Error(result.error.message + (result.error.details ? ' | ' + result.error.details : ''));
  const { data: eqAtual, error: errLer } = await window.supa.from('equipe').select('*').order('nome');
  if (errLer) throw new Error('Salvo, mas erro ao recarregar: ' + errLer.message);
  equipe = eqAtual || [];
  window._scaCache = window._scaCache || {};
  window._scaCache.equipe = equipe;
  renderizarEquipe();
  cancelarMembro();
  _msgEq('✅ Membro salvo com sucesso!', 'ok');
  setTimeout(() => { msg.style.display = 'none'; }, 3500);
} catch(e) {
  _msgEq('❌ Erro ao salvar: ' + e.message, 'err');
  console.error('[salvarMembro]', e);
}}

function editarMembro(i) {
const m = equipe[i];
console.log('[editarMembro] dados do membro:', JSON.stringify(m));
document.getElementById('equipe-form').style.display = 'block';
document.getElementById('equipe-form-titulo').textContent = '✏️ Editar Membro';
document.getElementById('mem-id').value    = m.id              || '';
document.getElementById('mem-nome').value  = m.nome            || '';
document.getElementById('mem-cpf').value   = m.cpf             || '';
document.getElementById('mem-nasc').value  = m.data_nascimento || '';
document.getElementById('mem-crea').value  = m.crea_cfb        || '';
document.getElementById('mem-cel').value   = m.celular         || '';
document.getElementById('mem-email').value = m.email           || '';
// Seleciona o cargo normalizando para evitar diferenças de encoding
const sel = document.getElementById('mem-cargo');
const cargo = (m.cargo || '').trim();
sel.value = '';
const norm = function(s){ return (s||'').normalize('NFC').trim(); };
let found = false;
Array.from(sel.options).forEach(function(opt) {
  if (norm(opt.value) === norm(cargo) || norm(opt.text) === norm(cargo)) {
    sel.value = opt.value; found = true;
  }
});
if (!found && cargo) {
  console.warn('[editarMembro] cargo "' + cargo + '" não encontrado nas opções — adicionando dinamicamente');
  const tmpOpt = document.createElement('option');
  tmpOpt.value = cargo; tmpOpt.text = cargo + ' (salvo anteriormente)';
  sel.insertBefore(tmpOpt, sel.options[1]);
  sel.value = cargo;
}
document.getElementById('equipe-form').scrollIntoView({ behavior: 'smooth' });}

