function escaparXml(str) {
return String(str || '')
.replace(/&/g, '&amp;')
.replace(/</g, '&lt;')
.replace(/>/g, '&gt;')
.replace(/"/g, '&quot;');}

function substituirVariaveisNoXml(xml, dados) {
var chaves = Object.keys(dados);
var i, chave, valorSafe, tag1, tag2, tag3, tag4, tag5, tag6;

// Primeira passagem: substitui variáveis quando estão intactas no XML
for (i = 0; i < chaves.length; i++) {
chave = chaves[i];
valorSafe = escaparXml(dados[chave]);
tag1 = '&lt;&lt;' + chave + '&gt;&gt;';
tag2 = '&lt;&lt; ' + chave + ' &gt;&gt;';
tag3 = '{{' + chave + '}}';
tag4 = '{{ ' + chave + ' }}';
tag5 = '<<' + chave + '>>';
tag6 = '<< ' + chave + ' >>';
while (xml.indexOf(tag1) >= 0) { xml = xml.split(tag1).join(valorSafe); }
while (xml.indexOf(tag2) >= 0) { xml = xml.split(tag2).join(valorSafe); }
while (xml.indexOf(tag3) >= 0) { xml = xml.split(tag3).join(valorSafe); }
while (xml.indexOf(tag4) >= 0) { xml = xml.split(tag4).join(valorSafe); }
while (xml.indexOf(tag5) >= 0) { xml = xml.split(tag5).join(valorSafe); }
while (xml.indexOf(tag6) >= 0) { xml = xml.split(tag6).join(valorSafe); }}

// Segunda passagem: trata parágrafos onde a variável foi fragmentada em múltiplos runs pelo Word
var temFragmentado = xml.indexOf('&lt;&lt;') >= 0 || xml.indexOf('{{') >= 0;
if (!temFragmentado) return xml;

xml = xml.replace(/(<w:p[ >][\s\S]*?<\/w:p>)/g, function(par) {
var temVar = par.indexOf('&lt;&lt;') >= 0 || par.indexOf('{{') >= 0;
if (!temVar) return par;
var runMatches = [];
var re = /(<w:t[^>]*>)([\s\S]*?)(<\/w:t>)/g;
var m;
while ((m = re.exec(par)) !== null) {
runMatches.push({ idx: m.index, full: m[0], open: m[1], text: m[2], close: m[3] });}
if (!runMatches.length) return par;
var textoJunto = runMatches.map(function(r) { return r.text; }).join('');
var textoNovo = textoJunto;
for (i = 0; i < chaves.length; i++) {
chave = chaves[i];
valorSafe = escaparXml(dados[chave]);
tag1 = '&lt;&lt;' + chave + '&gt;&gt;';
tag2 = '&lt;&lt; ' + chave + ' &gt;&gt;';
tag3 = '{{' + chave + '}}';
tag4 = '{{ ' + chave + ' }}';
tag5 = '<<' + chave + '>>';
tag6 = '<< ' + chave + ' >>';
while (textoNovo.indexOf(tag1) >= 0) { textoNovo = textoNovo.split(tag1).join(valorSafe); }
while (textoNovo.indexOf(tag2) >= 0) { textoNovo = textoNovo.split(tag2).join(valorSafe); }
while (textoNovo.indexOf(tag3) >= 0) { textoNovo = textoNovo.split(tag3).join(valorSafe); }
while (textoNovo.indexOf(tag4) >= 0) { textoNovo = textoNovo.split(tag4).join(valorSafe); }
while (textoNovo.indexOf(tag5) >= 0) { textoNovo = textoNovo.split(tag5).join(valorSafe); }
while (textoNovo.indexOf(tag6) >= 0) { textoNovo = textoNovo.split(tag6).join(valorSafe); }}
if (textoNovo === textoJunto) return par;
var resultado = par;
for (var j = runMatches.length - 1; j >= 0; j--) {
var r = runMatches[j];
var novoConteudo = j === 0 ? r.open + textoNovo + r.close : r.open + '' + r.close;
resultado = resultado.substring(0, r.idx) + novoConteudo + resultado.substring(r.idx + r.full.length);
}
return resultado;
});
return xml;}

async function preencherDocx(arrayBuffer, dados) {
var zip = new JSZip();
await zip.loadAsync(arrayBuffer.slice(0));
var xmlFiles = ['word/document.xml','word/header1.xml','word/footer1.xml',
'word/header2.xml','word/footer2.xml'];
for (var fi = 0; fi < xmlFiles.length; fi++) {
var fileName = xmlFiles[fi];
if (!zip.files[fileName]) continue;
var xml = await zip.files[fileName].async('string');
xml = substituirVariaveisNoXml(xml, dados);
zip.file(fileName, xml);}
return zip.generateAsync({
type: 'blob',
mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
});}

