async function restaurarDadosDeObjeto(obj) {
window._scaCache = window._scaCache || {};
if (obj.empresa || obj.empresa_dados) {
const emp = obj.empresa || obj.empresa_dados;
window._scaCache.empresa = emp;
if (window.fbSalvar) await window.fbSalvar('empresa', 'empresa', emp);}
if (obj.equipe) {
equipe = obj.equipe;
window._scaCache.equipe = obj.equipe;
if (window.supa) {
  for (const m of obj.equipe) {
    if (m.id) await window.supa.from('equipe').upsert(m, {onConflict:'id'});
    else await window.supa.from('equipe').insert(m);
  }
}}
if (obj.logo_url || obj.empresa_logo_url) {
const url = obj.logo_url || obj.empresa_logo_url;
window._scaCache.empresa_logo_url = url;
if (window.fbSalvar) await window.fbSalvar('empresa', 'empresa', { logo_url: url });}
if (obj.clientes && obj.clientes.length) {
for (const c of obj.clientes) {
if (c && c.cpf && window.fbSalvar) {
const cpfKey = c.cpf.replace(/\D/g,'');
if (cpfKey) await window.fbSalvar('clientes', cpfKey, c);}}
window.clientes = obj.clientes;
clientes = obj.clientes;
// Reseta navegação para o primeiro cliente após restaurar
clIdx = 0;
window.clIdx = 0;
clModoEdicao = false;
exibirCliente(0);
if (typeof atualizarDropdownElaboracao === 'function') atualizarDropdownElaboracao();
if (window.recarregarClientes) window.recarregarClientes();}
try { renderizarEquipe(); } catch(e) {}}

