async function fazerBackupNuvem() {
const btn = document.getElementById('btn-bkp-nuvem');
const statusEl = document.getElementById('bkp-status-geral');
function mostrarStatus(msg, tipo) {
  statusEl.style.display = 'block';
  statusEl.textContent = msg;
  statusEl.style.background = tipo==='ok'?'#d4edda':tipo==='err'?'#f8d7da':'#fff3cd';
  statusEl.style.color = tipo==='ok'?'#155724':tipo==='err'?'#721c24':'#856404';}
if (!supa) { mostrarStatus('❌ Erro de conexão com o Supabase.','err'); return; }
btn.disabled = true; btn.textContent = '⏳ Salvando...';
try {
  const dados = coletarTodosOsDados();
  const ts = new Date().toISOString().slice(0,19).replace('T','_').replace(/:/g,'-');
  const id = 'backup_' + ts + '_' + Date.now();
  const { error } = await supa.from('backups').upsert({
    id, created_at: new Date().toISOString(),
    descricao: 'Backup manual — ' + new Date().toLocaleString('pt-BR'),
    payload: JSON.stringify(dados),
    num_clientes:    dados.clientes      ? dados.clientes.length : 0,
    num_equipe:      dados.equipe        ? dados.equipe.length : 0,
    num_empresa:     dados.empresa && Object.keys(dados.empresa).length > 0 ? 1 : 0,
    num_participantes:   dados.participantes   ? dados.participantes.length : 0,
    num_agricola:        dados.producao_agricola ? dados.producao_agricola.length : 0,
    num_pecuaria:        dados.producao_pecuaria ? dados.producao_pecuaria.length : 0,
    num_propriedades:    dados.propriedades    ? dados.propriedades.length : 0,
  }, { onConflict: 'id' });
  if (error) throw error;
  mostrarStatus('✅ Backup salvo com sucesso! (' + new Date().toLocaleString('pt-BR') + ')', 'ok');
  listarBackupsNuvem();
} catch(e) {
  mostrarStatus('❌ Erro ao salvar backup: ' + (e.message || e), 'err');
} finally {
  btn.disabled = false; btn.innerHTML = '&#9729;&#65039; Salvar Backup no Supabase';}}

async function sincronizarTudo() {
  const btn = document.getElementById('btn-sync-tudo');
  const st  = document.getElementById('sync-tudo-status');
  const mostrar = (msg, tipo) => {
    st.style.display = '';
    st.style.background = tipo==='ok'?'#d4edda':tipo==='err'?'#f8d7da':'#fff3cd';
    st.style.color = tipo==='ok'?'#155724':tipo==='err'?'#721c24':'#856404';
    st.innerHTML = msg;
  };
  if (!window.supa) { mostrar('❌ Supabase não conectado.','err'); return; }
  btn.disabled = true; btn.textContent = '⏳ Sincronizando...';
  let okClientes=0, erroClientes=0;
  const JSONB = ['dados_pessoais','endereco','bancarios','participantes','agricola','pecuaria','propriedade','operacao_atual','operacoes','anexos'];
  const lista = window.clientes || [];
  for (const c of lista) {
    if (!c || !c.cpf) continue;
    const cpfKey = c.cpf.replace(/\D/g,'');
    if (!cpfKey) continue;
    try {
      const raiz = {}, jsonb = {};
      Object.keys(c).forEach(k => {
        if (k === 'id') return;
        if (JSONB.includes(k)) jsonb[k] = c[k];
        else raiz[k] = c[k];
      });
      const { error: e1 } = await window.supa.from('clientes').upsert({ id: cpfKey, ...raiz }, { onConflict: 'id' });
      if (e1) throw e1;
      if (Object.keys(jsonb).length > 0) {
        const { error: e2 } = await window.supa.from('clientes').update(jsonb).eq('id', cpfKey);
        if (e2) throw e2;
      }
      okClientes++;
    } catch(e) { erroClientes++; console.warn('Erro sync cliente:', c.nome, e); }
  }
  try {
    const emp = (window._scaCache && window._scaCache.empresa) || {};
    if (Object.keys(emp).length > 0) await window.fbSalvar('empresa', 'empresa', emp);
  } catch(e) { console.warn('Erro sync empresa:', e); }
  try {
    const eq = (window._scaCache && window._scaCache.equipe) || window.equipe || [];
    if (eq.length > 0) {
      for (const m of eq) {
        if (m.id) await window.supa.from('equipe').upsert(m, {onConflict:'id'}).catch(()=>{});
        else await window.supa.from('equipe').insert(m).catch(()=>{});
      }
    }
  } catch(e) { console.warn('Erro sync equipe:', e); }
  btn.disabled = false; btn.textContent = '🔄 Sincronizar Tudo Agora';
  if (erroClientes === 0) {
    mostrar('✅ Sincronização completa! <b>' + okClientes + '</b> cliente(s) + empresa + equipe enviados ao Supabase.', 'ok');
  } else {
    mostrar('⚠️ ' + okClientes + ' cliente(s) sincronizado(s), ' + erroClientes + ' com erro.', 'warn');
  }
}



