// Exibe o botão de Colaboradores no menu conforme o perfil
function aplicarVisibilidadeColaboradores(perfil) {
  const btn   = document.getElementById('nav-btn-colaboradores');
  const badge = document.getElementById('colab-badge');
  if (!btn) return;

  if (perfil === 'gerente' || perfil === 'admin') {
    btn.style.display = 'inline-flex';
  } else {
    btn.style.display = 'none';
  }

  if (badge) {
    if (perfil === 'admin') {
      badge.textContent = '👑 Administrador';
      badge.style.background = '#fef3c7';
      badge.style.color = '#92400e';
      badge.style.border = '1px solid #fbbf24';
    } else if (perfil === 'gerente') {
      badge.textContent = '🔑 Gerente';
      badge.style.background = '#d4edda';
      badge.style.color = '#1a5c38';
      badge.style.border = '1px solid #b8c9a8';
    }
  }

  // Admin pode excluir e alterar perfis
  window._SCA_PODE_EXCLUIR_USER  = (perfil === 'admin');
  window._SCA_PODE_ALTERAR_PERFIL = (perfil === 'admin');

  // Gerente NÃO vê a opção de criar gerente — só comum
  // A restrição já existe no HTML (option value="gerente") mas reforçamos aqui
  const selectPerfil = document.getElementById('colab-perfil');
  if (selectPerfil && perfil === 'gerente') {
    // Remove a opção "gerente" do select de cadastro se gerente estiver logado
    const optGerente = selectPerfil.querySelector('option[value="gerente"]');
    if (optGerente) optGerente.remove();
  }
}

// ── Carregar lista de colaboradores ─────────────────────────
window.carregarColaboradores = async function () {
  // Bloqueia acesso se perfil for comum
  if (window.SCA_PERFIL === 'comum') {
    console.warn('[SCA] Acesso negado: comum não pode ver colaboradores.');
    return;
  }

  const lista = document.getElementById('colab-lista');
  if (!lista || !window.supa) return;
  lista.innerHTML = '<span style="color:#999;font-style:italic;padding:14px;display:block;">Carregando...</span>';

  try {
    const { data, error } = await window.supa
      .from('perfis')
      .select('id, perfil, email, created_at, senha_hash')
      .order('created_at', { ascending: false });

    if (error) throw error;

    if (!data || data.length === 0) {
      lista.innerHTML = '<p style="padding:14px;color:#999;font-style:italic;">Nenhum colaborador cadastrado ainda.</p>';
      return;
    }

    const podeExcluir      = window._SCA_PODE_EXCLUIR_USER;
    const podeAlterarPerfil = window._SCA_PODE_ALTERAR_PERFIL;
    const perfilAtual      = window.SCA_PERFIL;

    lista.innerHTML = data.map((u, i) => {
      const bgRow = i % 2 === 0 ? '#fff' : '#f9f9f9';

      const perfilLabel = {
        admin:   '👑 Admin',
        gerente: '🔑 Gerente',
        comum:   '👤 Comum',
      }[u.perfil] || u.perfil;
      const perfilColor = {
        admin:   '#92400e',
        gerente: '#1a5c38',
        comum:   '#1a2a4a',
      }[u.perfil] || '#333';
      const perfilBg = {
        admin:   '#fef3c7',
        gerente: '#d4edda',
        comum:   '#e8edf5',
      }[u.perfil] || '#eee';

      const dt = u.created_at
        ? new Date(u.created_at).toLocaleDateString('pt-BR')
        : '—';

      // Select de perfil removido da listagem

      // Botão Ver senha — somente admin
      const btnVerSenha = (perfilAtual === 'admin' && u.senha_hash && u.perfil !== 'admin') ? `
        <button onclick="verSenhaColaborador('${u.id}', '${u.email}', this)"
          style="background:#1a5c38;color:#fff;border:none;border-radius:6px;padding:5px 10px;font-size:.74rem;cursor:pointer;">
          👁️ Ver
        </button>` : '';

      // Botão Editar senha — somente admin
      const btnEditarSenha = (perfilAtual === 'admin' && u.senha_hash && u.perfil !== 'admin') ? `
        <button onclick="editarSenhaColaborador('${u.id}', '${u.email}')"
          style="background:#f39c12;color:#fff;border:none;border-radius:6px;padding:5px 10px;font-size:.74rem;cursor:pointer;">
          ✏️ Editar
        </button>` : '';

      // Botão excluir — só admin
      const btnExcluir = (podeExcluir && u.perfil !== 'admin') ? `
        <button onclick="excluirColaborador('${u.id}', this)"
          style="background:#e74c3c;color:#fff;border:none;border-radius:6px;padding:5px 10px;font-size:.74rem;cursor:pointer;">
          🗑️
        </button>` : '';

      return `
        <div style="display:flex;align-items:center;gap:6px;padding:10px 14px;background:${bgRow};border-bottom:1px solid #e8edda;flex-wrap:nowrap;overflow:hidden;">
          <div style="font-size:1.1rem;flex-shrink:0;">👤</div>
          <div style="flex:1;overflow:hidden;">
            <div style="font-weight:700;color:#1a2a4a;font-size:.84rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${u.email || u.id}</div>
          </div>
          ${btnVerSenha}
          ${btnEditarSenha}
          ${btnExcluir}
          <span style="font-size:.72rem;font-weight:700;padding:3px 10px;border-radius:12px;background:${perfilBg};color:${perfilColor};white-space:nowrap;flex-shrink:0;">
            ${perfilLabel}
          </span>
        </div>`;
    }).join('');

  } catch (e) {
    lista.innerHTML = `<p style="padding:14px;color:#e74c3c;font-weight:700;">❌ Erro ao carregar: ${e.message || e}</p>`;
    console.warn('[SCA] Erro carregarColaboradores:', e);
  }
};

// ── Cadastrar novo colaborador ───────────────────────────────
// Gerente: só cria perfil 'comum'
// Admin:   cria 'comum' ou 'gerente'
window.cadastrarColaborador = async function () {
  // Bloqueia se for comum (não deveria chegar aqui, mas garantia extra)
  if (window.SCA_PERFIL === 'comum') return;

  const email    = document.getElementById('colab-email')?.value?.trim();
  const senha    = document.getElementById('colab-senha')?.value?.trim();
  const perfil   = document.getElementById('colab-perfil')?.value || 'comum';
  const statusEl = document.getElementById('colab-invite-status');

  function showStatus(msg, ok) {
    if (!statusEl) return;
    statusEl.style.display = 'block';
    statusEl.textContent   = msg;
    statusEl.style.background = ok ? '#d4edda' : '#f8d7da';
    statusEl.style.color      = ok ? '#155724' : '#721c24';
    statusEl.style.border     = '1px solid ' + (ok ? '#c3e6cb' : '#f5c6cb');
    if (ok) setTimeout(() => { statusEl.style.display = 'none'; }, 5000);
  }

  if (!email || !email.includes('@')) { showStatus('❌ Digite um e-mail válido.', false); return; }
  if (!senha || senha.length < 6)     { showStatus('❌ A senha deve ter no mínimo 6 caracteres.', false); return; }

  // Gerente só pode criar perfil 'comum' — bloqueia tentativa de criar gerente
  if (window.SCA_PERFIL === 'gerente' && perfil !== 'comum') {
    showStatus('❌ Gerência só pode cadastrar colaboradores comuns.', false);
    return;
  }

  showStatus('⏳ Cadastrando colaborador...', true);

  try {
    const { data: { session } } = await window.supa.auth.getSession();
    const token = session?.access_token;

    const resp = await fetch(window.SUPA_URL + '/functions/v1/convidar-usuario', {
      method: 'POST',
      headers: {
        'Content-Type':  'application/json',
        'Authorization': 'Bearer ' + token,
        'apikey':        window.SUPA_KEY,
      },
      body: JSON.stringify({ email, senha, perfil }),
    });

    const json = await resp.json();
    if (!resp.ok || json.error) throw new Error(json.error || json.message || 'Erro desconhecido');

    // Salva senha criptografada na tabela perfis para consulta futura
    try {
      const senhaCifrada = await window.scaCifrar(senha);
      await window.supa
        .from('perfis')
        .update({ senha_hash: senhaCifrada })
        .eq('email', email);
    } catch (eSenha) {
      console.warn('[SCA] Aviso: senha não salva no perfil:', eSenha);
    }

    showStatus('✅ Colaborador cadastrado com sucesso! E-mail: ' + email, true);
    limparFormColab();
    setTimeout(() => carregarColaboradores(), 1200);

  } catch (e) {
    showStatus('❌ Erro: ' + (e.message || e), false);
    console.warn('[SCA] Erro cadastrarColaborador:', e);
  }
};

// ── Limpar formulário ────────────────────────────────────────
window.limparFormColab = function () {
  const el = id => document.getElementById(id);
  if (el('colab-email'))  el('colab-email').value  = '';
  if (el('colab-senha'))  el('colab-senha').value  = '';
  if (el('colab-perfil')) el('colab-perfil').value = 'comum';
  const s = el('colab-invite-status');
  if (s) s.style.display = 'none';
};

// ── Toggle mostrar/ocultar senha ─────────────────────────────
window.toggleSenhaColab = function () {
  const input = document.getElementById('colab-senha');
  const btn   = document.getElementById('btn-toggle-senha');
  if (!input) return;
  if (input.type === 'password') {
    input.type = 'text';
    if (btn) btn.textContent = '🙈';
  } else {
    input.type = 'password';
    if (btn) btn.textContent = '👁️';
  }
};

// ── Ver senha de colaborador (somente admin) ─────────────────
window.verSenhaColaborador = async function (userId, email, btnEl) {
  if (window.SCA_PERFIL !== 'admin') return;

  try {
    const { data, error } = await window.supa
      .from('perfis')
      .select('senha_hash')
      .eq('id', userId)
      .single();

    if (error || !data?.senha_hash) {
      alert('⚠️ Senha não disponível para este colaborador.');
      return;
    }

    const senhaDecifrada = await window.scaDecifrar(data.senha_hash);

    const modal = document.createElement('div');
    modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);display:flex;align-items:center;justify-content:center;z-index:9999;';
    modal.innerHTML = `
      <div style="background:#fff;border-radius:12px;padding:24px;max-width:360px;width:90%;box-shadow:0 8px 32px rgba(0,0,0,.3);">
        <div style="font-weight:700;color:#7d3c98;font-size:1rem;margin-bottom:14px;">🔑 Senha do Colaborador</div>
        <div style="font-size:.82rem;color:#666;margin-bottom:8px;">E-mail: <strong>${email}</strong></div>
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:16px;">
          <input id="modal-senha-colab" type="password" value="${senhaDecifrada}" readonly
            style="flex:1;padding:8px 12px;border:1px solid #ce93d8;border-radius:7px;font-size:.9rem;background:#f9f9f9;"/>
          <button onclick="const i=document.getElementById('modal-senha-colab');i.type=i.type==='password'?'text':'password';this.textContent=i.type==='password'?'👁️':'🙈';"
            style="background:#7d3c98;color:#fff;border:none;border-radius:7px;padding:7px 11px;cursor:pointer;font-size:.85rem;">👁️</button>
          <button onclick="navigator.clipboard.writeText('${senhaDecifrada}').then(()=>{this.textContent='✅';setTimeout(()=>this.textContent='📋',1500);})"
            style="background:#1a5c38;color:#fff;border:none;border-radius:7px;padding:7px 11px;cursor:pointer;font-size:.85rem;">📋</button>
        </div>
        <button onclick="this.closest('[style*=fixed]').remove()"
          style="width:100%;background:#888;color:#fff;border:none;border-radius:8px;padding:9px;font-family:'Nunito',sans-serif;font-size:.87rem;font-weight:700;cursor:pointer;">
          Fechar
        </button>
      </div>`;
    document.body.appendChild(modal);
    modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });

  } catch (e) {
    alert('❌ Erro ao recuperar senha: ' + (e.message || e));
  }
};


