// ── Salvar nova senha de colaborador ─────────────────────────
window.salvarNovaSenhaColaborador = async function (userId, email) {
  const input     = document.getElementById('modal-editar-senha-colab');
  const statusEl  = document.getElementById('modal-editar-status');
  const salvarBtn = document.getElementById('modal-editar-salvar-btn');

  function showStatus(msg, ok) {
    if (!statusEl) return;
    statusEl.style.display    = 'block';
    statusEl.textContent      = msg;
    statusEl.style.background = ok ? '#d4edda' : '#f8d7da';
    statusEl.style.color      = ok ? '#155724' : '#721c24';
    statusEl.style.border     = '1px solid ' + (ok ? '#c3e6cb' : '#f5c6cb');
  }

  const novaSenha = input?.value?.trim();
  if (!novaSenha || novaSenha.length < 6) {
    showStatus('❌ A senha deve ter no mínimo 6 caracteres.', false);
    return;
  }

  if (salvarBtn) { salvarBtn.disabled = true; salvarBtn.textContent = '⏳ Salvando...'; }

  try {
    const { data: { session } } = await window.supa.auth.getSession();
    const token = session?.access_token;

    const resp = await fetch(window.SUPA_URL + '/functions/v1/convidar-usuario', {
      method: 'PATCH',
      headers: {
        'Content-Type':  'application/json',
        'Authorization': 'Bearer ' + token,
        'apikey':        window.SUPA_KEY,
      },
      body: JSON.stringify({ userId, senha: novaSenha }),
    });

    const json = await resp.json();
    if (!resp.ok || json.error) throw new Error(json.error || json.message || 'Erro desconhecido');

    const senhaCifrada = await window.scaCifrar(novaSenha);
    await window.supa
      .from('perfis')
      .update({ senha_hash: senhaCifrada })
      .eq('id', userId);

    showStatus('✅ Senha alterada com sucesso!', true);
    if (salvarBtn) { salvarBtn.disabled = false; salvarBtn.textContent = '💾 Salvar'; }

  } catch (e) {
    showStatus('❌ Erro: ' + (e.message || e), false);
    if (salvarBtn) { salvarBtn.disabled = false; salvarBtn.textContent = '💾 Salvar'; }
  }
};

// ── Alterar perfil (só admin) ────────────────────────────────
window.alterarPerfilColaborador = async function (userId, novoPerfil) {
  if (window.SCA_PERFIL !== 'admin') {
    console.warn('[SCA] Acesso negado: apenas admin pode alterar perfis.');
    return;
  }
  try {
    const { error } = await window.supa
      .from('perfis')
      .update({ perfil: novoPerfil })
      .eq('id', userId);
    if (error) throw error;
    console.log('[SCA] ✅ Perfil atualizado:', userId, '->', novoPerfil);
  } catch (e) {
    alert('❌ Erro ao alterar perfil: ' + (e.message || e));
    carregarColaboradores();
  }
};

// ── Excluir colaborador (só admin) ───────────────────────────
window.excluirColaborador = async function (userId, btnEl) {
  if (window.SCA_PERFIL !== 'admin') {
    console.warn('[SCA] Acesso negado: apenas admin pode excluir usuários.');
    return;
  }
  if (!confirm('Excluir este colaborador permanentemente?\nEle perderá o acesso ao sistema imediatamente.')) return;

  if (btnEl) { btnEl.disabled = true; btnEl.textContent = '⏳'; }

  try {
    const { data: { session } } = await window.supa.auth.getSession();
    const token = session?.access_token;

    const resp = await fetch(window.SUPA_URL + '/functions/v1/convidar-usuario', {
      method: 'DELETE',
      headers: {
        'Content-Type':  'application/json',
        'Authorization': 'Bearer ' + token,
        'apikey':        window.SUPA_KEY,
      },
      body: JSON.stringify({ userId }),
    });

    const json = await resp.json();
    if (!resp.ok) throw new Error(json.error || 'Erro ao excluir');

    carregarColaboradores();
  } catch (e) {
    alert('❌ Erro ao excluir: ' + (e.message || e));
    if (btnEl) { btnEl.disabled = false; btnEl.textContent = '🗑️'; }
  }
};

