// ── Registrar evento no Supabase ─────────────────────────────
window.registrarLogSeguranca = async function (tipo, descricao, email) {
  try {
    const emailAtual = email || window.SCA_EMAIL || 'desconhecido';
    await window.supa.from('logs_seguranca').insert({
      tipo,
      descricao,
      email: emailAtual,
      criado_em: new Date().toISOString(),
    });
  } catch (e) {
    console.warn('[Monitor] Erro ao registrar log:', e.message || e);
  }
};

// ── Carregar painel de monitoramento ─────────────────────────
window.carregarMonitor = async function () {
  if (window.SCA_PERFIL !== 'admin') return;

  const painel = document.getElementById('painel-monitor');
  const lista  = document.getElementById('monitor-lista');
  if (!painel || !lista) return;

  painel.style.display = 'block';
  lista.innerHTML = '<div style="padding:10px;color:#888;font-style:italic;font-size:.82rem;">Carregando...</div>';

  try {
    // Busca os últimos 50 logs
    const { data, error } = await window.supa
      .from('logs_seguranca')
      .select('*')
      .order('criado_em', { ascending: false })
      .limit(50);

    if (error) throw error;

    // Contadores do dia
    const hoje = new Date().toISOString().slice(0, 10);
    const doDia = (data || []).filter(l => l.criado_em?.slice(0, 10) === hoje);
    document.getElementById('mon-ok')      .textContent = doDia.filter(l => l.tipo === 'login_ok').length;
    document.getElementById('mon-erro')    .textContent = doDia.filter(l => l.tipo === 'login_erro').length;
    document.getElementById('mon-devtools').textContent = doDia.filter(l => l.tipo === 'devtools').length;
    document.getElementById('mon-acoes')   .textContent = doDia.filter(l => l.tipo === 'acao').length;

    if (!data || data.length === 0) {
      lista.innerHTML = '<div style="padding:14px;color:#888;font-style:italic;font-size:.82rem;">Nenhum evento registrado.</div>';
      return;
    }

    const iconMap  = { login_ok: '✅', login_erro: '❌', devtools: '⚠️', acao: '📝', acesso: '🔐' };
    const badgeMap = {
      login_ok:   { bg: '#d4edda', color: '#1a5c38', label: 'OK' },
      login_erro: { bg: '#f8d7da', color: '#721c24', label: 'Alerta' },
      devtools:   { bg: '#fff3cd', color: '#856404', label: 'Suspeito' },
      acao:       { bg: '#d1ecf1', color: '#0c5460', label: 'Ação' },
      acesso:     { bg: '#e2d9f3', color: '#4a235a', label: 'Acesso' },
    };

    const renderItem = l => {
      const icone = iconMap[l.tipo]  || '🔵';
      const badge = badgeMap[l.tipo] || { bg: '#eee', color: '#333', label: l.tipo };
      const hora  = l.criado_em ? new Date(l.criado_em).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) : '';
      const data_ = l.criado_em ? new Date(l.criado_em).toLocaleDateString('pt-BR') : '';
      return `
        <div style="display:flex;align-items:center;gap:8px;padding:10px 14px;border-bottom:1px solid #f0f0f0;font-size:.78rem;">
          <span style="font-size:1rem;flex-shrink:0;">${icone}</span>
          <div style="flex:1;">
            <div style="font-weight:700;color:#1a2a4a;">${l.email || 'desconhecido'}</div>
            <div style="color:#666;font-size:.7rem;margin-top:1px;">${l.descricao || ''}</div>
          </div>
          <div style="font-size:.68rem;color:#aaa;white-space:nowrap;text-align:right;">
            <div>${hora}</div><div>${data_}</div>
          </div>
          <span style="font-size:.66rem;font-weight:700;padding:2px 8px;border-radius:10px;white-space:nowrap;background:${badge.bg};color:${badge.color};">${badge.label}</span>
        </div>`;
    };

    const LIMITE_INICIAL = 3;
    const visiveis = data.slice(0, LIMITE_INICIAL);
    const ocultos  = data.slice(LIMITE_INICIAL);

    lista.innerHTML =
      visiveis.map(renderItem).join('') +
      (ocultos.length > 0 ? `
        <div id="monitor-ocultos" style="display:none;">
          ${ocultos.map(renderItem).join('')}
        </div>
        <div style="text-align:center;padding:10px;">
          <button id="btn-ver-mais-monitor"
            onclick="document.getElementById('monitor-ocultos').style.display='block';this.style.display='none';"
            style="font-size:.75rem;padding:5px 18px;border:1px solid #2c5282;border-radius:12px;background:#fff;color:#2c5282;cursor:pointer;">
            Ver mais (${ocultos.length} eventos)
          </button>
        </div>` : '');

  } catch (e) {
    lista.innerHTML = '<div style="padding:14px;color:#e74c3c;font-size:.82rem;">❌ Erro ao carregar logs: ' + (e.message || e) + '</div>';
  }
};

// ══════════════════════════════════════════════════════════════
// ── PAINEL DE USUÁRIOS BLOQUEADOS (somente Admin) ────────────
// ══════════════════════════════════════════════════════════════

window._SCA_DESBLOQUEAR_EMAIL = null;

window.carregarBloqueados = async function () {
  if (window.SCA_PERFIL !== 'admin') return;

  const painel = document.getElementById('painel-bloqueados');
  const lista  = document.getElementById('bloqueados-lista');
  const badge  = document.getElementById('bloqueados-badge');
  if (!painel || !lista) return;

  try {
    const { data, error } = await window.supa
      .from('perfis')
      .select('id, email, perfil, tentativas_login, created_at')
      .eq('bloqueado', true)
      .neq('perfil', 'admin')
      .order('created_at', { ascending: false });

    if (error) throw error;

    const total = data?.length || 0;

    if (total === 0) {
      painel.style.display = 'none';
      return;
    }

    painel.style.display = 'block';
    if (badge) badge.textContent = total + ' bloqueado' + (total > 1 ? 's' : '');

    const perfilLabel = { gerente: '🔑 Gerente', comum: '👤 Comum' };
    const perfilBg    = { gerente: '#fef3c7',    comum: '#f3f4f6' };
    const perfilColor = { gerente: '#92400e',     comum: '#374151' };

    lista.innerHTML = data.map(u => {
      const dt = u.created_at
        ? new Date(u.created_at).toLocaleString('pt-BR', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' })
        : '—';
      return `
        <div style="display:flex;align-items:center;gap:8px;padding:10px 14px;border-bottom:1px solid #fee2e2;background:#fff5f5;flex-wrap:wrap;">
          <div style="flex:1;min-width:0;">
            <div style="font-weight:700;color:#1f2937;font-size:.84rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${u.email}</div>
            <div style="font-size:.7rem;color:#9ca3af;margin-top:2px;">🚫 ${u.tentativas_login || 5} tentativas · ${dt}</div>
          </div>
          <span style="font-size:.7rem;font-weight:700;padding:3px 10px;border-radius:999px;background:${perfilBg[u.perfil]||'#eee'};color:${perfilColor[u.perfil]||'#333'};white-space:nowrap;">
            ${perfilLabel[u.perfil] || u.perfil}
          </span>
          <button onclick="abrirModalDesbloquear('${u.email}')"
            style="background:linear-gradient(135deg,#16a34a,#4caf50);color:#fff;border:none;padding:7px 12px;border-radius:8px;font-family:'Nunito',sans-serif;font-size:.78rem;font-weight:700;cursor:pointer;white-space:nowrap;box-shadow:0 2px 6px rgba(22,163,74,.25);">
            🔓 Desbloquear
          </button>
        </div>`;
    }).join('');

  } catch (e) {
    lista.innerHTML = '<div style="padding:14px;color:#e74c3c;font-size:.82rem;">❌ Erro: ' + (e.message || e) + '</div>';
  }
};

window.abrirModalDesbloquear = function (email) {
  window._SCA_DESBLOQUEAR_EMAIL = email;
  const el = document.getElementById('modal-desbloquear-email');
  if (el) el.textContent = email;
  const modal = document.getElementById('modal-desbloquear');
  if (modal) { modal.style.display = 'flex'; }
};

window.fecharModalDesbloquear = function () {
  const modal = document.getElementById('modal-desbloquear');
  if (modal) modal.style.display = 'none';
  window._SCA_DESBLOQUEAR_EMAIL = null;
};

window.confirmarDesbloquear = async function () {
  const email = window._SCA_DESBLOQUEAR_EMAIL;
  if (!email) return;
  window.fecharModalDesbloquear();

  try {
    const { error } = await window.supa
      .from('perfis')
      .update({ bloqueado: false, tentativas_login: 0 })
      .eq('email', email);

    if (error) throw error;

    window.registrarLogSeguranca && window.registrarLogSeguranca('acao', 'Usuário desbloqueado pelo admin: ' + email, window.SCA_EMAIL || 'admin');
    window.carregarBloqueados();

    // Toast de sucesso
    const t = document.createElement('div');
    t.textContent = '✅ ' + email + ' desbloqueado!';
    t.style.cssText = 'position:fixed;bottom:28px;left:50%;transform:translateX(-50%);background:#16a34a;color:#fff;padding:11px 22px;border-radius:999px;font-family:Nunito,sans-serif;font-weight:700;font-size:.88rem;z-index:99999;box-shadow:0 6px 20px rgba(22,163,74,.35);';
    document.body.appendChild(t);
    setTimeout(() => t.remove(), 3000);

  } catch (e) {
    alert('❌ Erro ao desbloquear: ' + (e.message || e));
  }
};
